<template>
    <div class="code-inputs" @paste="onPaste">
        <input
            v-for="(digit, id) in data.values"
            :key="id"
            :ref="el => data.inputs[id] = el"
            :value="data.values[id]"
            placeholder=" "
            type="text"
            inputmode="numeric"
            autocomplete="one-time-code"
            @input="onInput($event, id)"
            @focus="focusInput(id)"
            @keydown="onKeydown(id, $event)"
        />
            <!-- maxlength="1" -->
      </div>
</template>

<script setup>
    import { ref, watch, reactive, onMounted } from 'vue';
    const props = defineProps({
        count: { type: Number, default: 6 }
    });

    const data = reactive({
        values: ref(Array(props.count).fill('')),
        inputs: {}
    });

    const emit = defineEmits(['change']);

    const onPaste = (e) => {
        const pasteData = e.clipboardData.getData('text').trim();
        
        if (!/^\d+$/.test(pasteData)) {
            return;
        }

        const digits = pasteData.split('').slice(0, props.count);

        digits.forEach((char, index) => {
            data.values[index] = char;
        });

        const lastIndex = Math.min(digits.length, props.count - 1);
        focusInput(lastIndex);
        
        e.preventDefault();
    };

    // const onInput = (e, id) => {
    //     if (/^[0-9]$/.test(e.target.value)) {
    //         data.values[id] = +e.target.value;
    //         nextInput(id);
    //     } else {
    //         data.values[id] = '';
    //     }
    // };

    const onInput = (e, id) => {
        const inputVal = e.target.value;
        
        // 1. Если это вставка или автозаполнение (длина > 1)
        if (inputVal.length > 1) {
            const digits = inputVal
                .replace(/\D/g, '')          // Оставляем только цифры
                .split('')
                .slice(0, props.count);      // Обрезаем до нужной длины
                
            digits.forEach((char, index) => {
                if (index < props.count) {
                    data.values[index] = char;
                }
            });

            // Фокусим последнее заполненное поле
            focusInput(Math.min(digits.length - 1, props.count - 1));
            return;
        }

        // 2. Обычный ввод одного символа
        if (/^[0-9]$/.test(inputVal)) {
            data.values[id] = inputVal;
            nextInput(id);
        } else {
            // Очищаем, если ввели не цифру (или нажали Del)
            data.values[id] = '';
        }
    };


    const focusInput = (id) => {
        if (data.inputs[id]) {
            data.inputs[id].focus();
        }
    };

    const nextInput = (id) => {
        if (id + 1 < props.count) {
            focusInput(id + 1);
        }
    };

    const onKeydown = (id, event) => {
        if (event.key === 'Backspace' && !data.values[id] && id > 0) {
            data.values[id - 1] = '';
            focusInput(id - 1);
        }
    };

    watch(data.values, (newValues) => {
        if (data.values.every(item => /^[0-9]$/.test(item))) {
            emit('change', data.values.join(''));
        } else {
            emit('change', null);
        }
    });

    onMounted(() => {
        focusInput(0);
    })
</script>

<style lang="scss" scoped>
    .code-inputs {
        display: flex;
        flex-direction: row;
        gap: 10px;

        input {
            @include input;
            font: var(--font-h5);
            font-weight: bold;
            padding: 0;
            text-align: center;

            &:focus,
            &:hover,
            &:not(:placeholder-shown) {
                padding-top: 0;
                padding-bottom: 2px;
            }
        }  
    }
</style>
