<template>
    <BaseModal
        :isLoading="data.loading"
        :name="props.name"
        :mobileMode="true"
        :closeOutside="true"
        class="modal-code"
    >
        <template v-slot:title>{{ data.title }}</template>

        <template v-slot:content>
            <span class="description" v-html="data.description"></span>

            <Code @change="setCode" />

            <Button
                @click="verify"
                :disabled="!data.code"
                class="size-l"
                :name="data.verify"
            />
        </template>
    </BaseModal>
</template>

<script setup>
import { useI18n } from 'vue-i18n';
import { onMounted, reactive } from 'vue';
import { message } from '🔗/utils/utils';

import BaseModal from '🔗/components/modals/BaseModal.vue';
import Button from '🔗/components/ui/Button.vue';
import Code from '🔗/components/ui/Code.vue';

import stores from '@/stores';
const modals = stores.modals();
const user = stores.user();

const { t } = useI18n();

const data = reactive({
    once: false,
    loading: false,
    code: '',

    title: '',
    description: '',
    verify: '',
    check: null
});

const props = defineProps({
    name: {
        type: String,
        default: 'code'
    }
});

const setCode = (code) => {
    data.code = code;

    if (data.code && !data.once) {
        data.once = true;
        verify();
    }
}

const verify = async () => {
    if (!data.check) {
        return;
    }

    data.loading = true;

    const payload = await data.check(data.code);

    if (!payload) {
        data.loading = false;
        return;
    }

    modals.close(props.name);
}


onMounted(() => {
    const payload = modals.getData(props.name);

    data.title = payload?.title;
    data.description = payload?.description;
    data.verify = payload?.verify;
    data.check = payload?.check;

    data.loading = false;
});

</script>

<style lang="scss">
    .modal-code {
        max-width: 420px;
    }
</style>

<style lang="scss" scoped>
    .description {
        padding: 0;
        text-align: center;
        font: var(--font-body-2);
        color: var(--dark-500);
    }

    .size-l {
        margin-top: 10px;
    }
</style>
